-- Ghana Tertiary UniConnect Dataset - part 11
-- Run parts sequentially in Supabase SQL Editor.

insert into public.departments (source_id, university_id, faculty_id, name) select 'vvu_theology_leadership_and_humanities_religious_studies', u.id, f.id, 'Religious Studies' from public.universities u join public.faculties f on f.source_id = 'vvu_theology_leadership_and_humanities' where u.source_id = 'vvu' and not exists (select 1 from public.departments where source_id = 'vvu_theology_leadership_and_humanities_religious_studies' or (university_id = u.id and name = 'Religious Studies'));
update public.departments set source_id = coalesce(source_id, 'vvu_theology_leadership_and_humanities_religious_studies'), faculty_id = (select id from public.faculties where source_id = 'vvu_theology_leadership_and_humanities') where source_id = 'vvu_theology_leadership_and_humanities_religious_studies' or (name = 'Religious Studies' and university_id = (select id from public.universities where source_id = 'vvu'));
